import Link from 'next/link';
import  fs from 'fs';
import path from 'path';
import matter from 'gray-matter';
import ServiceCard from '@/components/ServiceCard';


export default function BlogIndex() {
    // 1. Point to your logs directory
    const logsDirectory = path.join(process.cwd(), 'content/logs');

    // 2. Read all filenames in that folder
    const fileNames = fs.readdirSync(logsDirectory);

    // 3. Extract the metadata (frontmatter) from each file )
    const allLogsData = fileNames.map((fileName) => {
        const slug = fileName.replace(/\.md$/, '');
        const fullPath = path.join(logsDirectory, fileName);
        const fileContents = fs.readFileSync(fullPath, 'utf8');
        const { data } = matter(fileContents);

        return {
            slug, 
            title: data.title || "Untitled Log",
            date: data.date || "No Date",
            category: data.category || "General",
        };
    });


    return (
        <div className='max-w-4xl mx-auto py-20 px-6 dark:bg-gray-200 rounded-2xl my-10'>
            <h1 className='text-4xl font-black text-slate-900 mb-10'>Engineering Identity</h1>

            <div className="grid gap-8">
                {allLogsData.map((log) => (
                    <Link
                        key={log.slug}
                        href={`/blog/${log.slug}`}
                        className="group block p-6 bg-white border border-slate-slate-200 rounded-2xl shadow-sm hover:shadow-md hover:border-indigo-300 transition-all"
                    >
                        <div className="flex justify-between items-start">
                            <div>
                                <span className="text-xs font-bold text-indigo-600 uppercase tracking-widest"
                            >
                                {log.category}
                            </span>
                            <h2 className="text-2xl font-bold text-slate-900 group-hover:text-indigo-600 transition-colors duration-200 mt-1"
                            >{log.title}
                            </h2>
                            <p className="text-slate-500 mt-2">{log.date}</p>
                            </div>
                            <span className="text-slate-300 group-hover:text-indigo-400 text-2xl transition-colors duration-200">→</span>
                        </div>
                    </Link>
                ))}
            </div>
        </div>
    );
}